import{_ as i,o as a,c as e,ag as o}from"./chunks/framework.CAXxHpAX.js";const p=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md"}'),r={name:"guide/faq.md"};function t(n,l,s,d,u,c){return a(),e("div",null,[...l[0]||(l[0]=[o('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><p>这里收录跨工具共性问题。工具特定问题请参考对应工具页的&quot;常见报错&quot;部分。</p><h2 id="为什么改完设置后没有生效" tabindex="-1">为什么改完设置后没有生效? <a class="header-anchor" href="#为什么改完设置后没有生效" aria-label="Permalink to &quot;为什么改完设置后没有生效?&quot;">​</a></h2><p>可能原因:</p><ol><li><strong>未保存配置</strong>:某些工具需要手动保存配置文件或点击&quot;保存&quot;按钮</li><li><strong>未重新加载</strong>:某些工具需要重新加载配置或重启工具</li><li><strong>配置文件位置错误</strong>:修改了错误的配置文件(如全局配置 vs 项目配置)</li><li><strong>字段名错误</strong>:字段名拼写错误或大小写不匹配</li></ol><p>解决方法:</p><ul><li>确认已保存配置</li><li>尝试重新加载或重启工具</li><li>检查配置文件路径是否正确</li><li>对照工具页示例检查字段名</li></ul><h2 id="api-key-和-base-url-通常分别填在哪里" tabindex="-1">API Key 和 Base URL 通常分别填在哪里? <a class="header-anchor" href="#api-key-和-base-url-通常分别填在哪里" aria-label="Permalink to &quot;API Key 和 Base URL 通常分别填在哪里?&quot;">​</a></h2><p>不同工具的填写位置不同,但通常在以下位置之一:</p><ul><li><strong>设置面板</strong>:图形界面工具通常在&quot;设置&quot;或&quot;偏好设置&quot;中</li><li><strong>配置文件</strong>:CLI 工具通常在配置文件中(如 <code>config.yaml</code>、<code>settings.json</code>)</li><li><strong>环境变量</strong>:某些工具支持通过环境变量设置</li></ul><p>具体填写位置请参考对应工具的配置页面。</p><h2 id="如何判断工具是否真的在走自定义接口" tabindex="-1">如何判断工具是否真的在走自定义接口? <a class="header-anchor" href="#如何判断工具是否真的在走自定义接口" aria-label="Permalink to &quot;如何判断工具是否真的在走自定义接口?&quot;">​</a></h2><p>验证方法:</p><ol><li><strong>查看日志</strong>:如果工具提供日志,查看请求是否发送到自定义 Base URL</li><li><strong>发送测试请求</strong>:发送一个请求,观察是否从自定义接口返回结果</li><li><strong>检查错误提示</strong>:如果自定义接口不可用,工具应返回连接错误</li><li><strong>使用抓包工具</strong>:高级用户可以使用抓包工具查看实际请求地址</li></ol><h2 id="为什么有些工具还要求填模型名或-provider" tabindex="-1">为什么有些工具还要求填模型名或 Provider? <a class="header-anchor" href="#为什么有些工具还要求填模型名或-provider" aria-label="Permalink to &quot;为什么有些工具还要求填模型名或 Provider?&quot;">​</a></h2><p>某些工具需要明确指定模型或 Provider,原因包括:</p><ul><li><strong>多模型支持</strong>:工具支持多个模型,需要你选择使用哪个</li><li><strong>多服务商支持</strong>:工具支持多个服务商(如 OpenAI、Anthropic),需要你指定</li><li><strong>兼容模式</strong>:工具使用 OpenAI 兼容模式时,需要指定模型名</li></ul><p>模型名和 Provider 的填写方式请参考对应工具页的示例。</p><h2 id="为什么不同平台看到的界面略有不同" tabindex="-1">为什么不同平台看到的界面略有不同? <a class="header-anchor" href="#为什么不同平台看到的界面略有不同" aria-label="Permalink to &quot;为什么不同平台看到的界面略有不同?&quot;">​</a></h2><p>某些工具在不同平台(Windows、macOS、Linux)上的界面或配置路径略有不同:</p><ul><li><strong>配置文件路径</strong>:Windows 使用 <code>%USERPROFILE%</code>,macOS/Linux 使用 <code>~</code></li><li><strong>设置入口</strong>:菜单项位置可能不同</li><li><strong>环境变量设置</strong>:Windows 使用&quot;环境变量&quot;设置,macOS/Linux 使用 shell 配置文件</li></ul><p>工具页会标注重要的平台差异,请注意查看。</p><h2 id="为什么会出现-401-错误" tabindex="-1">为什么会出现 401 错误? <a class="header-anchor" href="#为什么会出现-401-错误" aria-label="Permalink to &quot;为什么会出现 401 错误?&quot;">​</a></h2><p><code>401 Unauthorized</code> 通常表示身份验证失败,可能原因:</p><ul><li>API Key 填错或已失效</li><li>API Key 与 Base URL 不匹配(来自不同服务商)</li><li>API Key 权限不足或已过期</li></ul><p>解决方法:</p><ul><li>检查 API Key 是否正确</li><li>确认 API Key 和 Base URL 来自同一服务商</li><li>到服务商控制台检查 API Key 状态</li></ul><h2 id="为什么会出现-404-错误" tabindex="-1">为什么会出现 404 错误? <a class="header-anchor" href="#为什么会出现-404-错误" aria-label="Permalink to &quot;为什么会出现 404 错误?&quot;">​</a></h2><p><code>404 Not Found</code> 通常表示请求地址错误,可能原因:</p><ul><li>Base URL 填错</li><li>Base URL 路径不正确(如缺少或多余 <code>/v1</code>)</li><li>模型名称错误(如果 URL 中包含模型名)</li></ul><p>解决方法:</p><ul><li>检查 Base URL 是否正确</li><li>对照工具页示例检查路径</li><li>检查模型名称是否正确</li></ul><h2 id="为什么模型列表为空" tabindex="-1">为什么模型列表为空? <a class="header-anchor" href="#为什么模型列表为空" aria-label="Permalink to &quot;为什么模型列表为空?&quot;">​</a></h2><p>某些工具会显示可用模型列表,如果列表为空,可能原因:</p><ul><li>Base URL 错误,无法连接到服务商</li><li>API Key 错误,无法获取模型列表</li><li>服务商不支持模型列表查询</li></ul><p>解决方法:</p><ul><li>检查 Base URL 和 API Key 是否正确</li><li>手动填写模型名(如果工具支持)</li><li>参考工具页示例直接填写配置</li></ul>',37)])])}const g=i(r,[["render",t]]);export{p as __pageData,g as default};
